class Solution {
public:
    int LIS(vector<int>& nums) {
        if (nums.size() == 0)
            return 0;

        int max = 0;
        for (int i = 0; i < nums.size(); i++) {
            for (int j = i + 1; j < nums.size(); j++) {
                if (nums[i] < nums[j])
                    max = max + 1;
            }
        }
        return max;
    }
};

